{"command":"cd /tmp && mkdir -p binlog-reader && cd binlog-reader && cat > binlog-reader.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.415" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'CSHARPEOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

Console.WriteLine("=== PROJECTS BUILT ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var proj in projects)
{
    var name = proj.Name;
    var config = proj.FindChildrenRecursive<Property>()
        .Where(p => p.Name == "Configuration")
        .Select(p => p.Value)
        .FirstOrDefault();
    var platform = proj.FindChildrenRecursive<Property>()
        .Where(p => p.Name == "Platform")
        .Select(p => p.Value)
        .FirstOrDefault();
    var tf = proj.FindChildrenRecursive<Property>()
        .Where(p => p.Name == "TargetFramework")
        .Select(p => p.Value)
        .FirstOrDefault();
    Console.WriteLine($"  Project: {name}");
    Console.WriteLine($"    Configuration: {config ?? "(not set)"} | Platform: {platform ?? "(not set)"} | TargetFramework: {tf ?? "(not set)"}");
}
Console.WriteLine();

Console.WriteLine("=== ERRORS ===");
var errors = build.FindChildrenRecursive<Error>();
foreach (var err in errors)
{
    Console.WriteLine($"  [{err.Code}] {err.Text}");
    Console.WriteLine($"    File: {err.File}");
    Console.WriteLine($"    Project: {err.ProjectFile}");
}
if (!errors.Any())
    Console.WriteLine("  (no errors found via Error nodes)");

Console.WriteLine();
Console.WriteLine("=== WARNINGS (first 20) ===");
var warnings = build.FindChildrenRecursive<Warning>().Take(20);
foreach (var w in warnings)
{
    Console.WriteLine($"  [{w.Code}] {w.Text}");
}

Console.WriteLine();
Console.WriteLine("=== MESSAGES WITH 'error' or 'missing' or 'failed' (first 30) ===");
var messages = build.FindChildrenRecursive<Message>()
    .Where(m => m.Text != null && (
        m.Text.Contains("error", StringComparison.OrdinalIgnoreCase) ||
        m.Text.Contains("missing", StringComparison.OrdinalIgnoreCase) ||
        m.Text.Contains("failed", StringComparison.OrdinalIgnoreCase) ||
        m.Text.Contains("not found", StringComparison.OrdinalIgnoreCase)
    ))
    .Take(30);
foreach (var m in messages)
{
    Console.WriteLine($"  {m.Text}");
}
